import{_ as a,o as e,c as l,a3 as i}from"./chunks/framework.CRbjHCyB.js";const b=JSON.parse('{"title":"Lint","description":"","frontmatter":{},"headers":[],"relativePath":"zh/clice/features/lint.md","filePath":"zh/clice/features/lint.md"}'),s={name:"zh/clice/features/lint.md"};function c(n,t,d,r,o,h){return e(),l("div",null,[...t[0]||(t[0]=[i('<h1 id="lint" tabindex="-1">Lint <a class="header-anchor" href="#lint" aria-label="Permalink to &quot;Lint&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>clice 集成 clang-tidy 作为内置代码检查引擎。与独立的 clang-tidy 逐个处理每个翻译单元不同，clice 的架构支持跨翻译单元协调以消除重复工作。</p><p><strong>用法</strong>：<code>clice lint</code>（尚未实现）</p><h2 id="当前状态" tabindex="-1">当前状态 <a class="header-anchor" href="#当前状态" aria-label="Permalink to &quot;当前状态&quot;">​</a></h2><ul class="contains-task-list"><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> 基本 clang-tidy 集成（单翻译单元、编辑器内诊断）</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> 通过 CLI 进行项目级 lint（<code>clice lint</code>）</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> 跨翻译单元头文件去重</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> 增量重新 lint（仅变更文件）</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Lint 结果缓存</li></ul><h2 id="跨翻译单元优化" tabindex="-1">跨翻译单元优化 <a class="header-anchor" href="#跨翻译单元优化" aria-label="Permalink to &quot;跨翻译单元优化&quot;">​</a></h2><h3 id="问题" tabindex="-1">问题 <a class="header-anchor" href="#问题" aria-label="Permalink to &quot;问题&quot;">​</a></h3><p>clang-tidy 独立处理每个翻译单元。被 N 个源文件包含的头文件会被检查 N 次 — 这是乘法级开销，使得大型代码库的项目级 lint 非常缓慢。</p><h3 id="clice-的方案" tabindex="-1">clice 的方案 <a class="header-anchor" href="#clice-的方案" aria-label="Permalink to &quot;clice 的方案&quot;">​</a></h3><p>作为持久化服务器，clice 掌握完整的编译图，因此可以：</p><ul class="contains-task-list"><li class="task-list-item"><input class="task-list-item-checkbox" checked="" disabled="" type="checkbox"> 追踪哪些头文件在多个翻译单元间共享</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> 对声明内容哈希以跳过先前翻译单元中已检查的相同声明</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> 带依赖感知的 lint 作业调度（共享头文件只 lint 一次，传播结果）</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> 按内容哈希 + 检查配置键缓存头文件 lint 结果</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> 单文件诊断去重（基本：移除单个翻译单元内的重复诊断）</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> 项目级诊断去重（高级：跨翻译单元中同一头文件的相同警告只显示一次）</li></ul><h3 id="预期加速" tabindex="-1">预期加速 <a class="header-anchor" href="#预期加速" aria-label="Permalink to &quot;预期加速&quot;">​</a></h3><p>对于具有 H 个共享头文件和 N 个翻译单元的项目，独立的 clang-tidy 的工作量为 O(N × H)。通过跨翻译单元去重，clice 的设计目标是增量检查 — 使每个头文件无论被多少翻译单元包含都只检查一次。</p><h2 id="clang-tidy-集成质量" tabindex="-1">clang-tidy 集成质量 <a class="header-anchor" href="#clang-tidy-集成质量" aria-label="Permalink to &quot;clang-tidy 集成质量&quot;">​</a></h2><p>影响语言服务器中 clang-tidy 诊断质量的问题：</p><ul class="contains-task-list"><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> 抑制来自系统头文件宏的 clang-tidy 警告（<a href="https://github.com/clangd/clangd/issues/1587" target="_blank" rel="noreferrer">clangd#1587</a>、<a href="https://github.com/clangd/clangd/issues/2000" target="_blank" rel="noreferrer">clangd#2000</a>）</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> 在预编译头中的预处理指令（头文件保护、宏）上运行检查（<a href="https://github.com/clangd/clangd/issues/2501" target="_blank" rel="noreferrer">clangd#2501</a>、<a href="https://github.com/clangd/clangd/issues/160" target="_blank" rel="noreferrer">clangd#160</a>）</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> 按检查类别配置诊断严重性（<a href="https://github.com/clangd/clangd/issues/1937" target="_blank" rel="noreferrer">clangd#1937</a>）</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> 支持加载 clang-tidy 插件（<a href="https://github.com/clangd/clangd/issues/1458" target="_blank" rel="noreferrer">clangd#1458</a>）</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Clang 静态分析器支持（<a href="https://github.com/clangd/clangd/issues/905" target="_blank" rel="noreferrer">clangd#905</a>）</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> 应用 clang-tidy 修复时清理替换内容（<a href="https://github.com/clangd/clangd/issues/429" target="_blank" rel="noreferrer">clangd#429</a>）</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> 按版本控制 diff 过滤诊断（<a href="https://github.com/clangd/clangd/issues/822" target="_blank" rel="noreferrer">clangd#822</a>）</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> NOLINT / NOLINTNEXTLINE / NOLINTBEGIN-END 注释抑制</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> <code>.clangd</code> 配置中的 <code>Diagnostics.ClangTidy</code> 配置</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> clang-tidy 性能的快速检查过滤</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> clang-tidy 的 fix-it 建议作为代码操作</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> 诊断元数据：检查名称、文档 URL、来源标签</li></ul><h2 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h2><p>遵守项目树中的标准 <code>.clang-tidy</code> 配置文件。</p><h2 id="变更记录" tabindex="-1">变更记录 <a class="header-anchor" href="#变更记录" aria-label="Permalink to &quot;变更记录&quot;">​</a></h2><table tabindex="0"><thead><tr><th>日期</th><th>变更</th><th>PR</th></tr></thead><tbody><tr><td>—</td><td>存根实现、依赖图追踪</td><td>—</td></tr></tbody></table>',21)])])}const p=a(s,[["render",c]]);export{b as __pageData,p as default};
